evals.prompt:
Svelte 5로 포팅 중인데 아래 컴포넌트가 무한 루프 에러를 내. 뭐가 문제인지 설명하고 고쳐줘.

<script lang="ts">
  let count = $state(0)
  let log = $state<string[]>([])

  // 카운트가 10 넘으면 리셋
  $effect(() => {
    if (count > 10) {
      count = 0
    }
    log = [...log, `count is ${count}`]
  })

  function increment() { count++ }
</script>

<button onclick={increment}>+</button>
<p>count = {count}</p>
<pre>{log.join('\n')}</pre>
